import React from "react";
import "./Header.css";

export default function Header() {
  return (
    <header className="header">
      <div className="logo">
        <a href="#hero">
          <img src="/logo.png" alt="MBTI Logo" />
        </a>
      </div>
      <nav className="nav">
        <ul>
          <li><a href="#hero">მთავარი</a></li>
          <li><a href="#mbti">MBTI განზომილებები</a></li>
          <li><a href="#science">მეცნიერული ხედვა</a></li>
          <li><a href="#start-test">დაიწყე ტესტი</a></li>
          <li><a href="">log in</a></li>
        </ul>
      </nav>
    </header>
  );
}
